            if e == 1 and o == 0:
                return [1]
            elif e == 0 and o == 1:
                return [2]
            else:
                return []

        if e == 0 and o == n * (n + 1) // 2:
            return [2] * n

        if e == n * (n + 1) // 2 and o == 0:
