        odd_count = 0

        for start in range(n):
            current_sum = 0
            for end in range(start, n):
                current_sum += arr[end]
                if current_sum % 2 == 0:
                    even_count += 1
                else:
                    odd_count += 1

        return even_count == e and odd_count == o

