def can_form_array(N: int, E: int, O: int) -> List[int]:
    if N == 0 or E < 0 or O < 0 or E + O != N * (N + 1) // 2:
        return [-1]

    if E == 0:
        return [1] * N

    if O == 0:
        return [2] * N

    arr = [0] * N
    arr[0] = 1

    for i in range(1, N):
        if E > 0 and O > 0:
            arr[i] = 1 + (arr[i - 1] % 2)
            if arr[i] % 2 == 0:
                E -= 1
            else:
                O -= 1
        elif E > 0:
            arr[i] = 1 + (arr[i - 1] % 2)
            E -= 1
        else:
            arr[i] = 2 + (arr[i - 1] % 2)
            O -= 1

    if E != 0 or O != 0:
        return [-1]

    return arr

