class Solution:
    def __init__(self):
        self.idx = 0

    def read_int(self):
        self.idx += 1
        return int(data[self.idx - 1])

    def read_list(self, n):
        self.idx += n
        return list(map(int, data[self.idx - n:self.idx]))

    def get_subarray_sums(self, arr):
        n = len(arr)
        prefix_sum = [0] * (n + 1)
        for i in range(n):
            prefix_sum[i + 1] = prefix_sum[i] + arr[i]
        subarray_sums = []
        for i in range(n):
            for j in range(i + 1, n + 1):
                subarray_sums.append(prefix_sum[j] - prefix_sum[i])
        return subarray_sums

    def find_array(self, n, e, o):
        if n == 0:
            if e == 0 and o == 0:
                return []
            else:
                return [-1]

        if n == 1:
            if e == 0 and o == 1:
                return [1]
            elif e == 1 and o == 0:
                return [2]
            else:
                return [-1]

        if e == n * (n + 1) // 2:
            return [2] * n

        if o == n * (n + 1) // 2:
            return [1] * n

        if n % 2 == 0:
            return [1, 2] + self.find_array(n - 2, e - 2, o)

        if n % 2 == 1:
            if e >= (n + 1) // 2 and o >= n // 2:
                return [1, 2] + self.find_array(n - 2, e - 2, o)
            elif e >= n // 2 and o >= (n + 1) // 2:
                return [2, 1] + self.find_array(n - 2, e - 2, o)
            else:
                return [-1]

    def main(self):
        t = self.read_int()
        results = []
        for _ in range(t):
            n = self.read_int()
            e = self.read_int()
            o = self.read_int()
            result = self.find_array(n, e, o)
            if result[0] != -1:
                results.append(' '.join(map(str, result)))
            else:
                results.append('-1')
        print('\n'.join(results))

