MOD = 10**9 + 7

def count_humble_matrices(N, M):
    if N == 1:
        return M % MOD
    if M == 1:
        return N % MOD

    dp = [[0] * (M + 1) for _ in range(N + 1)]
    dp[1][1] = 1

    for i in range(1, N + 1):
        for j in range(1, M + 1):
            if i > 1:
                dp[i][j] += dp[i - 1][j]
                dp[i][j] %= MOD
            if j > 1:
                dp[i][j] += dp[i][j - 1]
                dp[i][j] %= MOD

    return dp[N][M]

