        for x, y in sorted_roads:
            if merged_roads and merged_roads[-1][1] >= x - 1:
                merged_roads[-1][1] = max(merged_roads[-1][1], y)
            else:
                merged_roads.append([x, y])

        for i in range(len(merged_roads)):
            if i > 0 and merged_roads[i-1][1] + 1 == merged_roads[i][0]:
