def probability_of_meeting(T1, T2, t1, t2):
    if t1 == 0:
        return Fraction(t2, T2)
    elif t2 == 0:
        return Fraction(t1, T1)
    else:
        area_total = T1 * T2
        area_meeting = max(0, min(T1, T1 + t2) - max(0, T1 - t2)) * max(0, min(T2, T2 + t1) - max(0, T2 - t1))
        return Fraction(area_meeting, area_total)

