def expected_value(Y):
    n = len(Y)
    total_v = 0

    for perm in permutations(Y):
        v = 0
        stack = []
        for i in range(n):
            while stack and perm[i] >= stack[-1]:
                stack.pop()
            if not stack:
                v += i + 1
            else:
                v += i - stack[-1]
            stack.append(perm[i])
        total_v += v

    return round(total_v / factorial(n), 2)

def factorial(n):
    if n == 0:
        return 1
    result = 1
    for i in range(2, n + 1):
        result *= i
    return result

