import sys
from collections import defaultdict

def parse_input():
    input = sys.stdin.read
    data = input().split()
    n = int(data[0])
    m = int(data[1])
    expressions = {}
    index = 2
    for _ in range(n):
        var = data[index]
        index += 1
        expr = data[index]
        index += 1
        if expr.startswith('0b'):
            expressions[var] = expr
        else:
            op1, op2 = expr.split()[1], expr.split()[2]
            expressions[var] = (op1, expr.split()[0], op2)
    return n, m, expressions

def evaluate_expression(expr, values):
    if isinstance(expr, str) and expr.startswith('0b'):
        return int(expr, 2)
    else:
        op1, op, op2 = expr
        val1 = values[op1] if op1 != '?' else -1
        val2 = values[op2] if op2 != '?' else -1
        if val1 == -1 or val2 == -1:
            return None
        if op == 'AND':
            return val1 & val2
        elif op == 'OR':
            return val1 | val2
        elif op == 'XOR':
            return val1 ^ val2

def minimize_and_maximize_scores(n, m, expressions):
    min_value = float('inf')
    max_value = float('-inf')

    def backtrack(values):
        nonlocal min_value, max_value
        total = sum(evaluate_expression(expr, values) for expr in expressions.values())
        if total < min_value or (total == min_value and values['?'] < min_value):
            min_value = total
        if total > max_value or (total == max_value and values['?'] < max_value):
            max_value = total

        for i in range(2 ** m):
            values['?'] = i
            valid = True
            for expr in expressions.values():
                value = evaluate_expression(expr, values)
                if value is None:
                    valid = False
                    break
            if valid:
                backtrack(values.copy())

    backtrack({})

    min_binary = format(min_value, f'0{m}b')
    max_binary = format(max_value, f'0{m}b')

    return min_binary, max_binary

n, m, expressions = parse_input()
min_binary, max_binary = minimize_and_maximize_scores(n, m, expressions)
print(min_binary)
print(max_binary)

