def solve(N, M, H, A, B):
    max_time = 0
    current_time = 0
    current_floor = [1] * M

    while True:
        anyone_left = False
        for i in range(M):
            if current_floor[i] != B[i]:
                anyone_left = True
                if current_floor[i] < A[i]:
                    current_floor[i] += 1
                    current_time += 1
                else:
                    current_time += H

        if anyone_left:
            for i in range(M):
                if current_floor[i] == A[i]:
                    current_floor[i] += 1
                    current_time += 1
                    break

        if all(current_floor[j] == B[j] for j in range(M)):
            return current_time + (max(B) - min(A)) // M * H

