        self.index = 0

    def read_int(self):
        result = int(self.data[self.index])
        self.index += 1
        return result

    def solve(self):
        results = []
        T = self.read_int()
        for _ in range(T):
            N = self.read_int()
            K = self.read_int()
            Q = self.read_int()
            S = self.data[self.index]
            self.index += 1
            queries = [(self.read_int() - 1, self.read_int() - 1) for _ in range(Q)]

            def count_substrings_with_at_most_k_zeros_ones(left, right):
                count = 0
                zeros = ones = 0
                left_ptr = 0
                for right_ptr in range(right, left - 1, -1):
                    if S[right_ptr] == '0':
                        zeros += 1
                    else:
                        ones += 1
                    while zeros > K or ones > K:
                        if S[left_ptr] == '0':
                            zeros -= 1
                        else:
                            ones -= 1
                        left_ptr += 1
                    count += right_ptr - left_ptr + 1
                return count

            results.append([count_substrings_with_at_most_k_zeros_ones(L, R) for L, R in queries])

        return results

