from math import factorial

MOD = 1_000_000_007

def binomial_coefficient(n, k):
    if k > n:
        return 0
    return factorial(n) // (factorial(k) * factorial(n - k))

def count_ways(colors):
    total_balls = sum(colors)
    result = factorial(total_balls)

    for count in colors:
        if count > 1:
            result //= factorial(count)

    for i in range(1, len(colors)):
        result *= binomial_coefficient(sum(colors[:i]), sum(colors[:i+1]))
        result %= MOD

    return result

