    def can_move_to_group(group_points):
        queue = [(group_points[0], 0)]
        visited = set([group_points[0]])
        while queue:
            current, steps = heappop(queue)
            if len(visited) == len(group_points):
                return True
            for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                nx, ny = current[0] + dx * k, current[1] + dy * k
                new_point = (nx, ny)
