    for x in elements:
        for y in elements:
            if (x & y == 0):
                graph[x].append(y)
                graph[y].append(x)

    visited = [False] * (1 << n)
    count = 0

    for node in elements:
        if not visited[node]:
            queue = deque([node])
            visited[node] = True

            while queue:
                current = queue.popleft()

                for neighbor in graph[current]:
                    if not visited[neighbor]:
                        visited[neighbor] = True
