from functools import lru_cache

MOD = 10**9 + 7

@lru_cache(None)
def dp(r, c):
    if r == 1:
        return 2 ** c
    res = dp(r - 1, c)
    for i in range(1, c):
        res += dp(r - 1, i) * dp(r, c - i)
    return res % MOD

