MOD = 1_000_000_007

def count_random_pictures(n, m):
    if n == 1:
        return pow(2, m, MOD)
    if m == 1:
        return pow(2, n, MOD)

    dp = [[0] * (m + 1) for _ in range(n + 1)]
    dp[1][1] = 2

    for i in range(2, n + 1):
        dp[i][1] = dp[i - 1][1]
        for j in range(2, m + 1):
            dp[i][j] = (dp[i - 1][j] + dp[i][j - 1]) % MOD

    result = dp[n][m]
    return result

