def count_regular_sequences(n, s):
    m = len(s)
    if m > 2 * n:
        return 0

    # dp[i][j] will store the number of ways to fill j open brackets with i closing brackets
    dp = [[0] * (m + 1) for _ in range(m + 1)]
    dp[0][0] = 1

    for i in range(m):
        for j in range(i + 1):
            if j < i:
                dp[i + 1][j + 1] = (dp[i + 1][j + 1] + dp[i][j]) % MOD
            if j > 0:
                dp[i + 1][j - 1] = (dp[i + 1][j - 1] + dp[i][j]) % MOD

    def valid(state):
        balance = 0
        for char in state:
            if char == '(':
                balance += 1
            else:
                balance -= 1
            if balance < 0:
                return False
        return balance == 0

    total_ways = 0
    for i in range(n - m + 1):
        left_open = n - i - m // 2
        right_open = n - i + m // 2
        if left_open >= 0 and right_open >= 0:
            total_ways = (total_ways + dp[left_open][right_open]) % MOD

    return total_ways

