def count_sequences(n, s):
    m = len(s)
    dp = [[0] * (m + 1) for _ in range(m + 1)]
    dp[0][0] = 1

    for i in range(m + 1):
        for j in range(i + 1):
            if i > 0:
                dp[i][j] += dp[i - 1][j]
            if j > 0:
                dp[i][j] += dp[i][j - 1]
            if i > 0 and j > 0 and s[j - 1] == '(':
                dp[i][j] -= dp[i - 1][j - 1]
            dp[i][j] %= MOD

    total_ways = dp[m][m]

    def check_balance(seq):
        balance = 0
        for char in seq:
            if char == '(':
                balance += 1
            else:
                balance -= 1
            if balance < 0:
                return False
        return balance == 0

    def count_subsequences(seq):
        count = 0
        stack = []
        for char in seq:
            if char == '(':
                stack.append(char)
            else:
                if stack and stack[-1] == '(':
                    stack.pop()
                    count += len(stack) + 1
        return count

    result = 0
    for i in range(m, 2*n + 1):
        for j in range(m, i + 1):
            if dp[j][i-j] != 0:
                subseq = '('*j + s + ')'*(i-j)
                if check_balance(subseq):
                    result += dp[j][i-j] * count_subsequences(subseq)
                    result %= MOD

    return result

