def solve(n, m, a, b):
    a_set = set(a)
    b_set = set(b)

    count = 0

    for pos in b:
        if pos in a_set:
            continue

        left = pos - 1
        right = pos + 1

        while left >= -10**9 and left not in a_set:
            left -= 1

        while right <= 10**9 and right not in a_set:
            right += 1

        if left in a_set:
            if right in a_set:
                if abs(pos - left) < abs(right - pos):
                    left = None
                else:
                    right = None

            if left is not None:
                a_set.remove(left)
                a_set.add(pos)
                count += 1

        elif right in a_set:
            a_set.remove(right)
            a_set.add(pos)
            count += 1

    return count

