from collections import defaultdict

MOD = 10**9 + 7

def compute_f_values(n):
    f_values = [0] * (n + 1)
    for i in range(1, n + 1):
        for j in range(i, n + 1, i):
            f_values[j] += i
    return f_values

def preprocess(n):
    divisors = defaultdict(list)
    for i in range(1, n + 1):
        for j in range(i, n + 1, i):
            divisors[i].append(j)

    prefix_sum = [0] * (n + 1)
    for i in range(1, n + 1):
        prefix_sum[i] = prefix_sum[i - 1] + len(divisors[i])

    return prefix_sum, divisors

def main():
    input = sys.stdin.read
    data = input().split()

    n = int(data[0])
    A = list(map(int, data[1:n+1]))
    q = int(data[n+1])

