        query_type = data[index]
        if query_type == 'C':
            x = int(data[index + 1]) - 1
            y = int(data[index + 2]) - 1
            total_sum = 0
            for i in range(x, y + 1):
                total_sum += f_values[A[i]]
            results.append(total_sum % MOD)
        elif query_type == 'U':
