from collections import defaultdict

MOD = 10**9 + 7

def preprocess(n):
    factor_count = [defaultdict(int) for _ in range(n+1)]
    for i in range(1, n+1):
        x = i
        for p in range(2, int(i**0.5)+1):
            if x % p == 0:
                count = 0
                while x % p == 0:
                    x //= p
                    count += 1
                factor_count[i][p] += count
        if x > 1:
            factor_count[i][x] += 1

    prefix_sum = [[0] * (n+1) for _ in range(10**5 + 1)]
    for i in range(1, n+1):
        for p, exp in factor_count[i].items():
            for e in range(exp):
                prefix_sum[p][i] += prefix_sum[p][i-1] + (i // (p**(e+1)))

    return prefix_sum

def compute(prefix_sum, x):
    total = 0
    for p in range(1, 5*10**5 + 1):
        total += prefix_sum[p][x]
    return total % MOD

def main():
    input = sys.stdin.read
    data = input().split()

    n = int(data[0])
    A = list(map(int, data[1:n+1]))
    Q = int(data[n+1])
    queries = data[n+2:]

    prefix_sum = preprocess(max(A))

    index = n + 2
    results = []
    for q in range(Q):
        type_ = queries[index]
        if type_ == 'C':
            x = int(queries[index + 1]) - 1
            y = int(queries[index + 2]) - 1
            result = 0
            for i in range(x, y+1):
                result += compute(prefix_sum, A[i])
            results.append(result % MOD)
        elif type_ == 'U':
            x = int(queries[index + 1]) - 1
            y = int(queries[index + 2])
            A[x] = y

        index += 3

    for result in results:
        print(result)

