def is_convex(points):
    n = len(points)
    if n <= 3:
        return True
    prev_orientation = None
    for i in range(n):
        current_orientation = orientation(points[i], points[(i + 1) % n], points[(i + 2) % n])
        if current_orientation != 0:
            if prev_orientation is not None and prev_orientation != current_orientation:
                return False
            prev_orientation = current_orientation
    return True

def convex_hull(points):
    n = len(points)
    if n < 3:
        return points
    start = min(range(n), key=lambda i: (points[i][1], points[i][0]))
    hull = []
    while True:
        hull.append(points[start])
        end = (start + 1) % n
        for i in range(2, n):
            turn = orientation(hull[-2], hull[-1], points[i])
            if turn == 0:
                if points[end][1] < points[i][1]:
                    end = i
            elif turn == 2:
                end = i
        start = end
        if start == 0:
            break
    return hull

def find_permutation(points):
    n = len(points)
    hull = convex_hull(points)
    if len(hull) != n:
        return [-1]

    def dfs(path, visited):
        if len(path) == n:
            return path
        last_point = path[-1]
        next_points = sorted([p for p in points if p not in visited], key=lambda p: (-orientation(last_point, p, hull[(hull.index(last_point) + 1) % len(hull)]), p))
        for np in next_points:
            if orientation(last_point, np, hull[(hull.index(last_point) + 1) % len(hull)]) == 1:
                result = dfs(path + [np], visited | {np})
                if result:
                    return result
        return None

    for i in range(n):
        if orientation(points[i], points[(i + 1) % n], hull[(hull.index(points[i]) + 1) % len(hull)]) == 1:
            perm = dfs([points[i]], set([points[i]]))
            if perm:
                return [points.index(p) + 1 for p in perm]
    return [-1]

