        j = (i + 1) % n
        k = (j + 1) % n
        if ccw(points[i], points[j], points[k]) > 0:
            positive = True
        elif ccw(points[i], points[j], points[k]) < 0:
            negative = True
        if positive and negative:
            return False
    return True

def get_hull(points):
    n = len(points)
    if n <= 3:
        return points[:]
    lower = []
    upper = []
    for p in points:
        while len(lower) >= 2 and ccw(lower[-2], lower[-1], p) <= 0:
            lower.pop()
        lower.append(p)
        while len(upper) >= 2 and ccw(upper[-2], upper[-1], p) <= 0:
            upper.pop()
        upper.append(p)
    return lower[:-1] + upper[:-1]

def find_permutation(points):
    n = len(points)
    hull = get_hull(points)
    if not is_convex(hull):
        return [-1]

    def dfs(index, path):
        if index == n:
            return True
        for i in range(n):
            if not visited[i]:
                visited[i] = True
                path.append(i + 1)
                if dfs(index + 1, path):
                    return True
                path.pop()
                visited[i] = False
        return False

    visited = [False] * n
    for i in range(n):
        if not visited[i]:
            visited[i] = True
            if dfs(1, [i + 1]):
                return path
            visited[i] = False
    return [-1]

