class Solution:
    def __init__(self):
        self.idx = 0

    def read_int(self):
        val = int(data[self.idx])
        self.idx += 1
        return val

    def can_kill_zombies(self, n, c, h):
        max_rad = [0] * (n + 1)
        for i in range(n):
            left = max(0, i - c[i])
            right = min(n, i + c[i] + 1)
            max_rad[left] += 1
            max_rad[right] -= 1

        for i in range(1, n + 1):
            max_rad[i] += max_rad[i - 1]

        return all(max_rad[i] == h[i - 1] for i in range(1, n + 1))

def main():
    t = Solution().read_int()
    results = []
    for _ in range(t):
        n = Solution().read_int()
        c = [Solution().read_int() for _ in range(n)]
        h = [Solution().read_int() for _ in range(n)]
        result = "YES" if Solution().can_kill_zombies(n, c, h) else "NO"
        results.append(result)

