import sys
from collections import defaultdict
import heapq

def find(parent, x):
    if parent[x] != x:
        parent[x] = find(parent, parent[x])
    return parent[x]

def union(parent, rank, x, y):
    rootX = find(parent, x)
    rootY = find(parent, y)
    if rootX != rootY:
        if rank[rootX] > rank[rootY]:
            parent[rootY] = rootX
        elif rank[rootX] < rank[rootY]:
            parent[rootX] = rootY
        else:
            parent[rootY] = rootX
            rank[rootX] += 1

def kruskal(n, edges):
    parent = list(range(n))
    rank = [0] * n
    edges.sort(key=lambda x: x[2])
    mst_weight = 0
    for u, v, w in edges:
        if find(parent, u - 1) != find(parent, v - 1):
            union(parent, rank, u - 1, v - 1)
            mst_weight += w
    return mst_weight

def min_ugliness(n, m, edges):
    assigned_weights = defaultdict(int)
    for u, v, w in edges:
        assigned_weights[(min(u, v), max(u, v))] = w

    pre_assigned_edges = set()
    for u, v, _ in edges:
        pre_assigned_edges.add((min(u, v), max(u, v)))

    remaining_edges = []
    for u in range(1, n + 1):
        for v in range(u + 1, n + 1):
            if (u, v) not in pre_assigned_edges:
                remaining_edges.append((u, v, 0))

    for i in range(n * (n - 1) // 2 - m):
        for j in range(i + 1, n * (n - 1) // 2 - m):
            for k in range(j + 1, n * (n - 1) // 2 - m):
                u1, v1, _ = remaining_edges[i]
                u2, v2, _ = remaining_edges[j]
                u3, v3, _ = remaining_edges[k]

                # Calculate XOR sum
                xor_sum = (assigned_weights.get((u1, v1), 0) ^
                           assigned_weights.get((u2, v2), 0) ^
                           assigned_weights.get((u3, v3), 0))

                if xor_sum == 0:
                    new_edges = remaining_edges[:]
                    new_edges.remove((u1, v1, 0))
                    new_edges.remove((u2, v2, 0))
                    new_edges.remove((u3, v3, 0))

                    # Try to assign weights to make XOR sum zero
                    for e in new_edges:
                        if (e[0], e[1]) not in pre_assigned_edges:
                            assigned_weights[(min(e[0], e[1]), max(e[0], e[1]))] = e[2]
                            if len(assigned_weights) == n * (n - 1) // 2:
                                break

                    # Check if we can form a valid MST
                    if len(assigned_weights) == n * (n - 1) // 2:
                        return kruskal(n, [(u, v, assigned_weights[(min(u, v), max(u, v))]) for u, v in edges] + list(assigned_weights.items()))

    return float('inf')

